                .{
                    .signature = "a: @Vector(a_len, E)",
                    .documentation = null,
                },
                .{
                    .signature = "b: @Vector(b_len, E)",
                    .documentation = null,
                },
                .{
                    .signature = "comptime mask: @Vector(mask_len, i32)",
                    .documentation = null,
                },
            },
        },
